fn test_allocation_reduction() {
    use std::alloc::{GlobalAlloc, Layout, System};
    use std::sync::atomic::{AtomicUsize, Ordering};

    static ALLOC_COUNT: AtomicUsize = AtomicUsize::new(0);

    struct CountingAllocator;

    unsafe impl GlobalAlloc for CountingAllocator {
        unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
            ALLOC_COUNT.fetch_add(1, Ordering::Relaxed);
            System.alloc(layout)
        }
        // ... dealloc impl
    }

    // Count allocations with Vec implementation
    ALLOC_COUNT.store(0, Ordering::Relaxed);
    for word in test_words() {
        let _ = edge_ngrams_vec(word);
    }
    let vec_allocs = ALLOC_COUNT.load(Ordering::Relaxed);

    // Count allocations with ArrayVec implementation
    ALLOC_COUNT.store(0, Ordering::Relaxed);
    for word in test_words() {
        let _ = edge_ngrams_stack(word);
    }
    let stack_allocs = ALLOC_COUNT.load(Ordering::Relaxed);

    println!("Vec allocations: {}", vec_allocs);
    println!("ArrayVec allocations: {}", stack_allocs);

    // ArrayVec should have significantly fewer allocations
    assert!(stack_allocs < vec_allocs / 2,
        "ArrayVec should have <50% of Vec allocations");
}
